defmodule ProductsController do
  use Phoenix.Controller

  def index(conn, _params) do
    search = conn.params[:search]
    products =
      Ecto.Query
      |> from(p in Product, where fragment("name LIKE '%#{search}%'"))
      |> Repo.all()

    render conn, :products, products: products
  end
end